import React from 'react';

import {
  Button,
  Layout,
  Navbar,
  NavbarContainer,
  Paper,
  ContextMenu,
} from '../../components';
import { connect } from '../../utils';
import { controller } from './controller';
import { Training } from '../../model/types';
import { AddIcon } from '../../components/icons';

import style from './style.module.scss';

interface Props {
  data: Training[];
  onAdd: () => void;
  onDelete: (id: string) => void;
  onOpen: (id: string) => void;
}

type Controller = ReturnType<typeof controller>;

const PureTrainings: React.FC<Props> = (props) => {
  const { data } = props;

  const isData = data.length;

  const renderAddFirstTraining = () => {
    const { onAdd } = props;
    return (
      <Button
        skin="primary"
        font="nunito"
        className={style.addNew}
        onClick={onAdd}
        data-testid="add-first-training-button"
      >
        Add your 1st training
      </Button>
    );
  };

  const renderTrainings = () => {
    const { data, onDelete, onOpen } = props;
    return (
      <ul className={style.trainings} data-testid="trainings-list">
        {data.map((training) => {
          return (
            <li
              key={training.id}
              className={style.training}
              data-testid="training-item"
            >
              <Paper
                shadow="sm"
                p="xs"
                withBorder
                className={style.paper}
                onClick={() => onOpen(training.id)}
                data-testid="open-training-button"
              >
                {training.name}
              </Paper>
              <ContextMenu
                triggerButtonClassName={style.trainingContextMenu}
                items={[
                  {
                    label: 'Delete',
                    onClick: () => onDelete(training.id),
                  },
                ]}
              />
            </li>
          );
        })}
      </ul>
    );
  };

  const renderTopBar = () => {
    const { onAdd } = props;
    return (
      <NavbarContainer className={style.navbarContainer}>
        <Button
          skin="icon"
          size="large"
          onClick={onAdd}
          data-testid="add-training-button-top"
        >
          <AddIcon />
        </Button>
      </NavbarContainer>
    );
  };

  if (!isData) {
    return (
      <Layout bottomBar={<Navbar />} dataTestId="trainings-screen-no-data">
        <div className={style.screenAddNew}>{renderAddFirstTraining()}</div>
      </Layout>
    );
  }

  return (
    <Layout
      topBar={renderTopBar()}
      bottomBar={<Navbar />}
      dataTestId="trainings-screen"
    >
      <div className={style.screen}>{renderTrainings()}</div>
    </Layout>
  );
};

export const Trainings = connect<Controller, Props>(
  {
    controller,
  },
  (ctrl) => ({
    data: ctrl.getTrainings(),
    onAdd: ctrl.onAddTraining,
    onDelete: ctrl.onDeleteTraining,
    onOpen: ctrl.onOpenTraining,
  }),
)(PureTrainings);
